BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName ?stereotype WHERE {
  ?pkg vocab:NamedElement_name "Conceptual%20Design" .
  FILTER(CONTAINS(STR(?pkg), "APS"))
  ?pkg vocab:Element_ownedElement ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
  OPTIONAL { ?child vocab:Element_appliedStereotypeInstance ?stereotype }
}
LIMIT 100

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName ?commentBody WHERE {
  ?pkg vocab:NamedElement_name "Conceptual%20Design" .
  FILTER(CONTAINS(STR(?pkg), "APS"))
  ?pkg vocab:Element_ownedElement+ ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
  OPTIONAL { 
    ?comment rdf:type vocab:comment .
    ?comment vocab:Comment_annotatedElement ?child .
    ?comment vocab:Comment_body ?commentBody .
  }
}
LIMIT 100
